function extractErrorMessage(err) {
  if (!err)
    return "";
  if (typeof err === "string")
    return err;
  if (typeof err === "object") {
    const obj = err;
    if (typeof obj.message === "string")
      return obj.message;
    if (typeof obj.error === "string")
      return obj.error;
    try {
      return JSON.stringify(err);
    } catch {
      return "Unknown error";
    }
  }
  return String(err);
}

