      totalSpawned: states.length,
      completed: states.filter((s) => s.status === "completed").length,
      errored: states.filter((s) => s.status === "error").length,
      running: states.filter((s) => s.status === "running").length,
      maxDepth,
      totalDurationMs,
      byAgentType
