async function getCodebasePatternsForPrompt(cwd) {
  const patterns = await extractCodebasePatterns(cwd);
  if (patterns.length === 0)
    return "";
  const lines = ["## Codebase Patterns (Study These First)", ""];
  for (const pattern of patterns) {
    lines.push(`- ${pattern}`);
  }
  lines.push("");
  return lines.join(`
`);
}
// src/utils/process.ts
import { spawn as spawn16 } from "child_process";
async function runProcess(command, args = [], options = {}) {
  const { cwd, env, timeout = 0, spawnOptions = {} } = options;
  return new Promise((resolve6) => {
    const child = spawn16(command, args, {
      cwd,
      env: env ? { ...process.env, ...env } : process.env,
      ...spawnOptions
    });
    let stdout = "";
    let stderr = "";
    let killed = false;
    let timeoutHandle;
    if (timeout > 0) {
      timeoutHandle = setTimeout(() => {
        killed = true;
        child.kill("SIGTERM");
      }, timeout);
    }
    child.stdout?.on("data", (data) => {
      stdout += data.toString();
    });
    child.stderr?.on("data", (data) => {
      stderr += data.toString();
    });
    child.on("error", (error48) => {
      if (timeoutHandle)
        clearTimeout(timeoutHandle);
      resolve6({
        exitCode: null,
        signal: null,
        stdout,
        stderr: stderr + error48.message,
        success: false
      });
    });
    child.on("close", (exitCode, signal) => {
      if (timeoutHandle)
        clearTimeout(timeoutHandle);
      resolve6({
        exitCode,
        signal: killed ? "SIGTERM" : signal,
        stdout,
        stderr,
        success: exitCode === 0
      });
    });
  });
}

// src/engine/auto-commit.ts
async function hasUncommittedChanges(cwd) {
  const result = await runProcess("git", ["status", "--porcelain"], { cwd });
  if (!result.success) {
    throw new Error(`git status failed: ${result.stderr.trim() || "unknown error (exit code " + result.exitCode + ")"}`);
  }
  return result.stdout.trim().length > 0;
}
async function performAutoCommit(cwd, taskId, taskTitle) {
  let hasChanges;
  try {
    hasChanges = await hasUncommittedChanges(cwd);
  } catch (err) {
    return {
      committed: false,
      error: err instanceof Error ? err.message : String(err)
    };
  }
  if (!hasChanges) {
    return {
      committed: false,
      skipReason: "no uncommitted changes"
    };
  }
  const addResult = await runProcess("git", ["add", "-A"], { cwd });
  if (!addResult.success) {
    return {
      committed: false,
      error: `git add failed: ${addResult.stderr.trim() || "unknown error"}`
    };
  }
  const commitMessage = `feat: ${taskId} - ${taskTitle}`;
  const commitResult = await runProcess("git", ["commit", "-m", commitMessage], { cwd });
  if (!commitResult.success) {
    return {
      committed: false,
      error: `git commit failed: ${commitResult.stderr.trim() || "unknown error"}`
    };
  }
  const shaResult = await runProcess("git", ["rev-parse", "--short", "HEAD"], { cwd });
  const commitSha = shaResult.success ? shaResult.stdout.trim() : undefined;
  return {
    committed: true,
    commitMessage,
    commitSha
  };
}

// src/templates/index.ts
init_engine();

// src/engine/index.ts
var PROMISE_COMPLETE_PATTERN = /<promise>\s*COMPLETE\s*<\/promise>/i;
var PRIMARY_RECOVERY_TEST_TIMEOUT_MS = 5000;
var PRIMARY_RECOVERY_TEST_PROMPT = 'Reply with just the word "ok".';
var MAX_ENGINE_LIVE_STREAM_CHARS = 250000;
var MAX_ITERATION_HISTORY_STREAM_CHARS = 1e5;
var OUTPUT_TRUNCATED_PREFIX = `[...output truncated in memory...]
`;
function appendWithCharLimit3(current, chunk, maxChars, prefix = OUTPUT_TRUNCATED_PREFIX) {
  return appendWithCharLimit(current, chunk, maxChars, prefix);
}
function toMemorySafeAgentResult(agentResult) {
  const safeStdout = appendWithCharLimit3("", agentResult.stdout, MAX_ITERATION_HISTORY_STREAM_CHARS);
  const safeStderr = appendWithCharLimit3("", agentResult.stderr, MAX_ITERATION_HISTORY_STREAM_CHARS);
  if (safeStdout === agentResult.stdout && safeStderr === agentResult.stderr) {
    return agentResult;
  }
  return {
    ...agentResult,
    stdout: safeStdout,
    stderr: safeStderr
  };
}
async function buildPrompt(task, config2, tracker) {
  const recentProgress = await getRecentProgressSummary(config2.cwd, 5);
  const codebasePatterns = await getCodebasePatternsForPrompt(config2.cwd);
  const trackerTemplate = tracker?.getTemplate?.();
  const prdContext = await tracker?.getPrdContext?.();
  const extendedContext = {
    recentProgress,
    codebasePatterns,
    prd: prdContext ?? undefined
  };
  const result = renderPrompt(task, config2, undefined, extendedContext, trackerTemplate);
  if (result.success && result.prompt) {
    return result.prompt;
  }
  console.error(`Template rendering failed: ${result.error}`);
  const lines = [];
  lines.push("## Task");
  lines.push(`**ID**: ${task.id}`);
  lines.push(`**Title**: ${task.title}`);
  if (task.description) {
    lines.push("");
    lines.push("## Description");
    lines.push(task.description);
  }
  lines.push("");
  lines.push("## Instructions");
  lines.push("Complete the task described above. When finished, signal completion with:");
  lines.push("<promise>COMPLETE</promise>");
  return lines.join(`
`);
}

