// src/interruption/handler.ts
var DEFAULT_DOUBLE_PRESS_WINDOW_MS = 1000;
function createInterruptHandler(options) {
  const doublePressWindowMs = options.doublePressWindowMs ?? DEFAULT_DOUBLE_PRESS_WINDOW_MS;
  let state = "idle";
  let lastSigintTime = 0;
  let signalHandler = null;
  function handleSigint() {
    const now = Date.now();
    const timeSinceLastSigint = now - lastSigintTime;
    lastSigintTime = now;
    if (timeSinceLastSigint < doublePressWindowMs && state !== "idle") {
      state = "force_quit";
      options.onForceQuit();
      return;
    }
    if (state === "idle") {
      state = "confirming";
      options.onShowDialog();
    } else if (state === "confirming") {
      state = "force_quit";
      options.onForceQuit();
    }
  }
  async function handleResponse(response) {
    if (state !== "confirming") {
      return;
    }
    if (response === "confirm") {
      state = "interrupting";
      options.onHideDialog();
      await options.onConfirmed();
    } else {
      state = "idle";
      options.onHideDialog();
      options.onCancelled();
    }
  }
  function getState() {
    return state;
  }
  function reset() {
    state = "idle";
    lastSigintTime = 0;
  }
  function install() {
    if (signalHandler) {
      return;
    }
    signalHandler = () => {
      handleSigint();
    };
    process.on("SIGINT", signalHandler);
  }
  function dispose() {
    if (signalHandler) {
      process.removeListener("SIGINT", signalHandler);
      signalHandler = null;
    }
  }
  install();
  return {
    handleSigint,
    handleResponse,
    getState,
    reset,
    dispose
  };
}
