function checkParallelGitPreflight(cwd) {
  const errors3 = [];
  const baseOptions = { cwd, encoding: "utf-8", timeout: 5000 };
  const isGitRepo = spawnSync("git", ["rev-parse", "--is-inside-work-tree"], baseOptions);
  if (isGitRepo.status !== 0 || isGitRepo.stdout.trim() !== "true") {
    errors3.push("Parallel mode requires running inside a git repository.");
    return { ok: false, errors: errors3 };
  }
  const branchResult = spawnSync("git", ["rev-parse", "--abbrev-ref", "HEAD"], baseOptions);
  const branch = branchResult.status === 0 ? branchResult.stdout.trim() : "";
  if (!branch || branch === "HEAD") {
    errors3.push("Parallel mode requires a named branch (detached HEAD is not supported).");
  }
  const trackedStatus = spawnSync("git", ["status", "--porcelain", "--untracked-files=no"], baseOptions);
  if (trackedStatus.status !== 0) {
    errors3.push("Unable to verify git working tree status.");
  } else if (trackedStatus.stdout.trim().length > 0) {
    errors3.push("Tracked working tree is not clean. Commit or stash tracked changes before parallel mode.");
  }
  const unmerged = spawnSync("git", ["ls-files", "-u"], baseOptions);
  if (unmerged.status !== 0) {
    const exitCode = unmerged.status;
    const stderr = unmerged.stderr.trim();
    errors3.push(stderr ? `Unable to verify unresolved merge entries (git ls-files -u exited with code ${exitCode}): ${stderr}` : `Unable to verify unresolved merge entries (git ls-files -u exited with code ${exitCode}).`);
  } else if (unmerged.stdout.trim().length > 0) {
    errors3.push("Repository has unresolved merge entries (git ls-files -u is not empty).");
  }
  const inProgressRefs = ["MERGE_HEAD", "REBASE_HEAD", "CHERRY_PICK_HEAD"];
  for (const ref of inProgressRefs) {
    const result = spawnSync("git", ["rev-parse", "-q", "--verify", ref], baseOptions);
    if (result.status === 0) {
      errors3.push(`Repository has an in-progress git operation (${ref}).`);
    }
  }
  return { ok: errors3.length === 0, errors: errors3 };
}
function parseRunArgs(args) {
  const options = {};
  for (let i = 0;i < args.length; i++) {
    const arg = args[i];
    const nextArg = args[i + 1];
    if (arg.startsWith("--sandbox=")) {
      const mode = arg.split("=")[1];
      if (mode === "bwrap" || mode === "sandbox-exec") {
        options.sandbox = {
          ...options.sandbox,
          enabled: true,
          mode
        };
      }
      continue;
    }
    switch (arg) {
      case "--epic":
        if (nextArg && !nextArg.startsWith("-")) {
          options.epicId = nextArg;
          i++;
        }
        break;
      case "--prd":
        if (nextArg && !nextArg.startsWith("-")) {
          options.prdPath = nextArg;
          i++;
        }
        break;
      case "--agent":
        if (nextArg && !nextArg.startsWith("-")) {
          options.agent = nextArg;
          i++;
        }
        break;
      case "--model":
        if (nextArg && !nextArg.startsWith("-")) {
          options.model = nextArg;
          i++;
        }
        break;
      case "--variant":
        if (nextArg && !nextArg.startsWith("-")) {
          options.variant = nextArg;
          i++;
        }
        break;
      case "--tracker":
        if (nextArg && !nextArg.startsWith("-")) {
          options.tracker = nextArg;
          i++;
        }
        break;
      case "--iterations":
        if (nextArg && !nextArg.startsWith("-")) {
          const parsed = parseInt(nextArg, 10);
          if (!isNaN(parsed)) {
            options.iterations = parsed;
          }
          i++;
        }
        break;
      case "--delay":
        if (nextArg && !nextArg.startsWith("-")) {
          const parsed = parseInt(nextArg, 10);
          if (!isNaN(parsed)) {
            options.iterationDelay = parsed;
          }
          i++;
        }
        break;
      case "--cwd":
        if (nextArg && !nextArg.startsWith("-")) {
          options.cwd = nextArg;
          i++;
        }
        break;
      case "--resume":
        options.resume = true;
        break;
      case "--force":
        options.force = true;
        break;
      case "--headless":
      case "--no-tui":
        options.headless = true;
        break;
      case "--no-setup":
        options.noSetup = true;
        break;
      case "--sandbox":
        options.sandbox = {
          ...options.sandbox,
          enabled: true,
          mode: "auto"
        };
        break;
      case "--no-sandbox":
        options.sandbox = {
          ...options.sandbox,
          enabled: false,
          mode: "off"
        };
        break;
      case "--no-network":
        options.sandbox = {
          ...options.sandbox,
          enabled: true,
          network: false
        };
        break;
      case "--prompt":
        if (nextArg && !nextArg.startsWith("-")) {
          options.promptPath = nextArg;
          i++;
        }
        break;
      case "--output-dir":
      case "--log-dir":
        if (nextArg && !nextArg.startsWith("-")) {
          options.outputDir = nextArg;
          i++;
        }
        break;
      case "--progress-file":
        if (nextArg && !nextArg.startsWith("-")) {
          options.progressFile = nextArg;
          i++;
        }
        break;
      case "--notify":
        options.notify = true;
        break;
      case "--no-notify":
        options.notify = false;
        break;
      case "--verify":
        options.verify = true;
        break;
      case "--listen":
        options.listen = true;
        options.headless = true;
        break;
      case "--listen-port":
        if (nextArg && !nextArg.startsWith("-")) {
          const parsed = parseInt(nextArg, 10);
          if (!isNaN(parsed) && parsed > 0 && parsed < 65536) {
            options.listenPort = parsed;
          }
          i++;
        }
        break;
      case "--rotate-token":
        options.rotateToken = true;
        break;
      case "--theme":
        if (nextArg && !nextArg.startsWith("-")) {
          options.themePath = nextArg;
          i++;
        }
        break;
      case "--serial":
      case "--sequential":
        options.serial = true;
        break;
      case "--parallel": {
        if (nextArg && !nextArg.startsWith("-")) {
          const parsed = parseInt(nextArg, 10);
          if (!isNaN(parsed) && parsed > 0) {
            options.parallel = parsed;
            i++;
          } else {
            options.parallel = true;
          }
        } else {
          options.parallel = true;
        }
        break;
      }
      case "--direct-merge":
        options.directMerge = true;
        break;
      case "--target-branch":
        if (nextArg && !nextArg.startsWith("-")) {
          options.targetBranch = nextArg;
          i++;
        }
        break;
      case "--task-range":
        if (nextArg && (!nextArg.startsWith("-") || /^-\d+$/.test(nextArg))) {
          const range = nextArg;
          if (range.includes("-")) {
            const dashIndex = range.indexOf("-");
            const startPart = range.substring(0, dashIndex);
            const endPart = range.substring(dashIndex + 1);
            const parsedStart = startPart ? parseInt(startPart, 10) : undefined;
            const parsedEnd = endPart ? parseInt(endPart, 10) : undefined;
            if ((parsedStart === undefined || !isNaN(parsedStart)) && (parsedEnd === undefined || !isNaN(parsedEnd)) && (parsedStart !== undefined || parsedEnd !== undefined)) {
              options.taskRange = {
                start: parsedStart,
                end: parsedEnd
              };
            }
          } else {
            const num = parseInt(range, 10);
            if (!isNaN(num)) {
              options.taskRange = { start: num, end: num };
            }
          }
          i++;
        }
        break;
    }
  }
  return options;
}
