function parseCwdArg(args) {
  for (let i = 0;i < args.length; i++) {
    const arg = args[i];
    if (arg.startsWith("--cwd=")) {
      return arg.substring("--cwd=".length);
    }
    if (arg === "--cwd" && i + 1 < args.length) {
      return args[i + 1];
    }
  }
  return process.cwd();
}
async function executeInfoCommand(args) {
  const jsonOutput = args.includes("--json");
  const copyable = args.includes("--copyable") || args.includes("-c");
  const cwd = parseCwdArg(args);
  if (args.includes("--help") || args.includes("-h")) {
    console.log(`
${BOLD2}ralph-tui info${RESET2} - Display system information for bug reports

${BOLD2}Usage:${RESET2} ralph-tui info [options]

${BOLD2}Options:${RESET2}
  ${DIM2}--json${RESET2}            Output in JSON format
  ${DIM2}--copyable, -c${RESET2}    Output in copyable format for bug reports
  ${DIM2}--cwd <path>${RESET2}      Working directory (default: current directory)
  ${DIM2}-h, --help${RESET2}        Show this help message

${BOLD2}Description:${RESET2}
  Collects and displays diagnostic information about your ralph-tui
  installation. This is useful for including in bug reports.

  Information collected:
  - ralph-tui version
  - Runtime (Bun/Node) version
  - Operating system details
  - Configuration file locations and status
  - Installed templates
  - Agent detection status
  - Tracker configuration
  - Installed skills (per agent and custom directory)

${BOLD2}Examples:${RESET2}
  ${CYAN2}ralph-tui info${RESET2}              # Display system info
  ${CYAN2}ralph-tui info --json${RESET2}       # JSON output for scripts
  ${CYAN2}ralph-tui info -c${RESET2}           # Copyable format for bug reports
`);
    return;
  }
  try {
    const info = await collectSystemInfo(cwd);
    if (jsonOutput) {
      console.log(JSON.stringify(info, null, 2));
    } else if (copyable) {
      console.log(formatForBugReport(info));
    } else {
      console.log();
      console.log(formatSystemInfo(info));
      console.log();
      console.log(`${DIM2}Tip: Use ${CYAN2}ralph-tui info -c${RESET2}${DIM2} for a copyable bug report format${RESET2}`);
      console.log();
    }
  } catch (error48) {
    console.error(`${YELLOW}Error collecting system info:${RESET2}`, error48 instanceof Error ? error48.message : error48);
    process.exit(1);
  }
}
