function printListenHelp() {
  console.log(`
ralph-tui listen - Start remote listener

Usage: ralph-tui listen [options]

Options:
  --port <port>     Port to bind to (default: 7890)
  --daemon, -d      Run as a background daemon
  --rotate-token    Generate a new token and invalidate the old one
  -h, --help        Show this help message

Description:
  Starts a WebSocket server for remote control of ralph-tui instances.
  This allows monitoring and controlling ralph-tui from a remote client.

  On first run, a secure authentication token is generated and displayed.
  Store this token securely - you will need it to connect remote clients.

Security:
  - If no token is configured, the server binds only to localhost (127.0.0.1)
  - With a token configured, the server binds to all interfaces (0.0.0.0)
  - All connections must authenticate with the token
  - All actions are logged to ~/.config/ralph-tui/audit.log

Token Management:
  - Token is stored in ~/.config/ralph-tui/remote.json
  - Use --rotate-token to generate a new token
  - Old tokens are immediately invalidated on rotation

Examples:
  ralph-tui listen                    # Start on default port 7890
  ralph-tui listen --port 8080        # Start on custom port
  ralph-tui listen --daemon           # Start as background daemon
  ralph-tui listen --rotate-token     # Rotate authentication token

Daemon Management:
  # Start daemon
  ralph-tui listen --daemon

  # Stop daemon
  kill $(cat ~/.config/ralph-tui/listen.pid)

  # Check if running
  ps -p $(cat ~/.config/ralph-tui/listen.pid) 2>/dev/null && echo "Running"
`);
}
// src/commands/remote.ts
function parseRemoteArgs(args) {
  const options = {};
  if (args.length === 0) {
    return options;
  }
  const subcommand = args[0];
  if (subcommand === "--help" || subcommand === "-h") {
    options.help = true;
    return options;
  }
  options.subcommand = subcommand;
  for (let i = 1;i < args.length; i++) {
    const arg = args[i];
    if (arg === "--help" || arg === "-h") {
      options.help = true;
    } else if (arg === "--token" && args[i + 1]) {
      options.token = args[i + 1];
      i++;
    } else if (arg === "--scope" && args[i + 1]) {
      const scopeValue = args[i + 1];
      if (scopeValue === "global" || scopeValue === "project") {
        options.scope = scopeValue;
      }
      i++;
    } else if (arg === "--preview") {
      options.preview = true;
    } else if (arg === "--force") {
      options.force = true;
    } else if (arg === "--all") {
      options.all = true;
    } else if (!arg.startsWith("-")) {
      if (!options.alias) {
        options.alias = arg;
      } else if (!options.hostPort) {
        options.hostPort = arg;
      }
    }
  }
  return options;
}
async function testRemoteConnection(host, port, token2) {
  const startTime = Date.now();
  return new Promise((resolve17) => {
    let ws = null;
    let settled = false;
    let timeout = null;
    const settleWith = (result) => {
      if (settled)
        return;
      settled = true;
      if (timeout)
        clearTimeout(timeout);
      if (ws) {
        ws.onopen = null;
        ws.onmessage = null;
        ws.onerror = null;
        ws.onclose = null;
        try {
          ws.close();
        } catch {}
      }
      resolve17(result);
    };
    timeout = setTimeout(() => {
      settleWith({ connected: false, error: "Connection timed out (5s)" });
    }, 5000);
    try {
      ws = new WebSocket(`ws://${host}:${port}`);
      ws.onopen = () => {
        const authMsg = {
          type: "auth",
          id: crypto.randomUUID(),
          timestamp: new Date().toISOString(),
          token: token2
        };
        ws.send(JSON.stringify(authMsg));
      };
      ws.onmessage = (event) => {
        const latencyMs = Date.now() - startTime;
        try {
          const msg = JSON.parse(event.data);
          if (msg.type === "auth_response") {
            if (msg.success) {
              settleWith({ connected: true, latencyMs });
            } else {
              settleWith({ connected: false, error: msg.error ?? "Authentication failed" });
            }
          } else {
            settleWith({ connected: false, error: `Unexpected response: ${msg.type}` });
          }
        } catch {
          settleWith({ connected: false, error: "Invalid response from server" });
        }
      };
      ws.onerror = () => {
        settleWith({ connected: false, error: "Connection failed" });
      };
      ws.onclose = (event) => {
        if (!event.wasClean && event.code !== 1000) {
          settleWith({ connected: false, error: `Connection closed: ${event.reason || "Unknown error"}` });
        }
      };
    } catch (err) {
      settleWith({ connected: false, error: err instanceof Error ? err.message : "Connection failed" });
    }
  });
}
